import React, { useState, useEffect } from 'react';
import { useParams } from 'react-router-dom';
import CertificateGenerator from '../../services/CertificateGenerator'; // Adjusted path
import LoadingSpinner from '../shared/LoadingSpinner';
import AlertMessage from '../shared/AlertMessage';

const CertificateViewerPage = () => {
  const { id, templateName } = useParams();
  const [certificateSvgUrl, setCertificateSvgUrl] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);

  useEffect(() => {
    const loadCertificate = async () => {
      setLoading(true);
      setError(null);
      try {
        // 1. Fetch certificate data (basic structure, adapt as needed)
        // This assumes you have an API endpoint to get raw certificate data by ID
        const response = await fetch(`/api/certificates/${id}`);
        if (!response.ok) {
          throw new Error(`Failed to fetch certificate: ${response.statusText}`);
        }
        
        const data = await response.json();
        const certificate = data.data;
        
        if (!certificate) {
          throw new Error('Certificate not found');
        }

        // Add templatePath if a specific template is requested via URL
        // (previewCertificate uses templatePath or defaults to simple-modern-certificate.svg)
        if (templateName) {
          certificate.templatePath = `/templates/${templateName}.svg`;
        } else {
          // 使用精美证书模板作为默认模板
          certificate.templatePath = '/templates/certificate-premium.svg';
        }

        // 2. Use the CertificateGenerator service to create the preview
        const svgUrl = await CertificateGenerator.previewCertificate({
          name: certificate.recipientName || certificate.name || '',
          course: certificate.program || '',
          date: certificate.issueDate || certificate.date || new Date().toISOString(),
          certificateId: certificate.certificateNumber || certificate._id || '',
          templatePath: certificate.templatePath
        });
        
        setCertificateSvgUrl(svgUrl);
      } catch (err) {
        console.error('Error loading certificate:', err);
        setError(err.message || 'Failed to load certificate');
      } finally {
        setLoading(false);
      }
    };

    if (id) {
      loadCertificate();
    }
  }, [id, templateName]);

  return (
    <div className="max-w-7xl mx-auto py-6 sm:px-6 lg:px-8">
      <div className="px-4 sm:px-0">
        <h2 className="text-2xl font-bold leading-7 text-gray-900 sm:text-3xl">
          Certificate
        </h2>
      </div>

      {loading ? (
        <div className="mt-6">
          <LoadingSpinner message="Loading certificate..." />
        </div>
      ) : error ? (
        <div className="mt-6">
          <AlertMessage
            type="error"
            message={{ title: 'Error', details: error }}
          />
        </div>
      ) : (
        <div className="mt-6 bg-white shadow overflow-hidden sm:rounded-lg">
          <div className="px-4 py-5 border-b border-gray-200 sm:px-6 flex justify-between items-center">
            <div>
              <h3 className="text-lg leading-6 font-medium text-gray-900">
                Certificate Preview
              </h3>
              <p className="mt-1 max-w-2xl text-sm text-gray-500">
                Your certificate has been generated successfully.
              </p>
            </div>
            <div>
              <a
                href={certificateSvgUrl}
                download="certificate.svg"
                className="inline-flex items-center px-4 py-2 border border-transparent rounded-md shadow-sm text-sm font-medium text-white bg-blue-600 hover:bg-blue-700 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-blue-500"
              >
                Download SVG
              </a>
            </div>
          </div>
          <div className="certificate-preview-container p-4 flex justify-center">
            {certificateSvgUrl && (
              <div className="certificate-preview-wrapper max-w-full overflow-auto">
                <img
                  src={certificateSvgUrl}
                  alt="Certificate Preview"
                  className="certificate-preview max-w-full h-auto"
                  style={{ maxHeight: '70vh' }}
                />
              </div>
            )}
          </div>
        </div>
      )}
    </div>
  );
};

export default CertificateViewerPage;
